125→// StartSubscriptions registers all NATS subscriptions for Job and Node APIs.
126→// Messages are delivered to buffered channels and processed by worker goroutines.
127→// Returns an error if the NATS client is not available or subscription fails.
128→func (api *NatsAPI) StartSubscriptions() error {
129→	client := nats.GetClient()
130→	if client == nil {
131→		cclog.Warn("NATS client not available, skipping API subscriptions")
132→		return nil
133→	}
134→
135→	if config.Keys.APISubjects != nil {
136→		s := config.Keys.APISubjects
137→
138→		if err := client.Subscribe(s.SubjectJobEvent, func(subject string, data []byte) {
139→			api.jobCh <- natsMessage{subject: subject, data: data}
140→		}); err != nil {
141→			return err
142→		}
143→
144→		if err := client.Subscribe(s.SubjectNodeState, func(subject string, data []byte) {
145→			api.nodeCh <- natsMessage{subject: subject, data: data}
146→		}); err != nil {
147→			return err
148→		}
149→
150→		cclog.Info("NATS API subscriptions started")
151→	}
152→	return nil
153→}
