380→// processNodestateEvent extracts and processes node state data from the InfluxDB message.
381→// Updates node states in the repository for all nodes in the payload.
382→func (api *NatsAPI) processNodestateEvent(msg lp.CCMessage) {
383→	v, ok := msg.GetEventValue()
384→	if !ok {
385→		cclog.Errorf("Nodestate event is missing event field with JSON payload")
386→		return
387→	}
388→
389→	var req UpdateNodeStatesRequest
390→
391→	dec := json.NewDecoder(strings.NewReader(v))
392→	dec.DisallowUnknownFields()
393→	if err := dec.Decode(&req); err != nil {
394→		cclog.Errorf("NATS nodestate: parsing request failed: %v", err)
395→		return
396→	}
397→
398→	repo := repository.GetNodeRepository()
399→	requestReceived := time.Now().Unix()
400→
401→	updates := make([]repository.NodeStateUpdate, 0, len(req.Nodes))
402→	for _, node := range req.Nodes {
403→		state := determineState(node.States)
404→		nodeState := schema.NodeStateDB{
405→			TimeStamp:       requestReceived,
406→			NodeState:       state,
407→			CpusAllocated:   node.CpusAllocated,
408→			MemoryAllocated: node.MemoryAllocated,
409→			GpusAllocated:   node.GpusAllocated,
410→			HealthState:     schema.MonitoringStateFull,
411→			JobsRunning:     node.JobsRunning,
412→		}
413→		updates = append(updates, repository.NodeStateUpdate{
414→			Hostname:  node.Hostname,
415→			Cluster:   req.Cluster,
416→			NodeState: &nodeState,
417→		})
418→	}
419→
420→	if err := repo.BatchUpdateNodeStates(updates); err != nil {
421→		cclog.Errorf("NATS nodestate: batch update for cluster %s failed: %v", req.Cluster, err)
422→	}
423→
424→	cclog.Debugf("NATS nodestate: updated %d node states for cluster %s", len(req.Nodes), req.Cluster)
425→}
426→
427→// handleNodeState processes node state update messages received via NATS using InfluxDB line protocol.
428→// The message must be in line protocol format with measurement="nodestate" and include:
429→//   - field "event" containing JSON payload (UpdateNodeStatesRequest)
430→//
431→// Example: nodestate event="{\"cluster\":\"testcluster\",\"nodes\":[...]}" 1234567890000000000
432→func (api *NatsAPI) handleNodeState(subject string, data []byte) {
433→	if len(data) == 0 {
434→		cclog.Warnf("NATS %s: received empty message", subject)
435→		return
436→	}
437→
438→	d := influx.NewDecoderWithBytes(data)
439→
440→	for d.Next() {
441→		m, err := receivers.DecodeInfluxMessage(d)
442→		if err != nil {
443→			cclog.Errorf("NATS %s: failed to decode InfluxDB line protocol message: %v", subject, err)
444→			return
445→		}
446→
447→		if !m.IsEvent() {
448→			cclog.Warnf("NATS %s: received non-event message, skipping", subject)
449→			continue
450→		}
451→
452→		if m.Name() == "nodestate" {
453→			api.processNodestateEvent(m)
454→		} else {
455→			cclog.Warnf("NATS %s: unexpected measurement name '%s', expected 'nodestate'", subject, m.Name())
456→		}
457→	}
458→}
