    HealthState     MonitoringState `db:"health_state"` // full/partial/failed
    HealthMetrics   string          `db:"health_metrics"` // JSON: {"missing":[...],"degraded":[...]}
    CpusAllocated   int             `db:"cpus_allocated"`
    MemoryAllocated int64           `db:"memory_allocated"`
    GpusAllocated   int             `db:"gpus_allocated"`
    JobsRunning     int             `db:"jobs_running"`
    NodeID          int64           `db:"node_id"` // Foreign key to node(id)
}
